import React, { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';

const Home = () => {
    const [currentSlide, setCurrentSlide] = useState(0);
    const slides = [
        [
            "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-1.jpg",
            "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-2.jpg",
            "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-3.jpg",
            "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-4.jpg"
        ],
        // 추가 슬라이드 배열들...
    ];

    const nextSlide = () => {
        setCurrentSlide((prev) => (prev + 1) % slides.length);
    };

    const prevSlide = () => {
        setCurrentSlide((prev) => (prev - 1 + slides.length) % slides.length);
    };

    return (
        <div className="flex flex-col items-center justify-center h-[calc(100vh-200px)] px-4">
            <div className="w-full max-w-6xl">
                <div className="relative mb-8">
                    <img 
                        className="w-full h-auto rounded-lg object-cover"
                        style={{maxHeight: 'calc(70vh - 200px)'}}
                        src="https://flowbite.s3.amazonaws.com/docs/gallery/featured/image.jpg" 
                        alt="Featured"
                    />
                </div>
                <div className="relative">
                    <div className="grid grid-cols-4 gap-4">
                        {slides[currentSlide].map((img, index) => (
                            <div key={index} className="aspect-w-1 aspect-h-1">
                                <img 
                                    className="w-full h-full rounded-lg object-cover"
                                    src={img} 
                                    alt={`Slide ${index + 1}`}
                                />
                            </div>
                        ))}
                    </div>
                    <button onClick={prevSlide} className="absolute left-0 top-1/2 transform -translate-y-1/2 bg-white bg-opacity-50 rounded-full p-2">
                        <ChevronLeft size={24} />
                    </button>
                    <button onClick={nextSlide} className="absolute right-0 top-1/2 transform -translate-y-1/2 bg-white bg-opacity-50 rounded-full p-2">
                        <ChevronRight size={24} />
                    </button>
                </div>
            </div>
        </div>
    );
};

export default Home;
